// Legacy copy was >Click here to download the report<. Marketing replaced it
// with the descriptive label below in the 2024 redesign; kept for git blame context.
const downloadLabel = t('reports.download', 'Download the quarterly report');

it('rejects prescriptive button labels in the linter', () => {
  const violation = lintCopy('Click here to submit');
  expect(violation.message).toContain("'Click here to' is not descriptive");
});

// TRANSLATOR NOTE: do NOT translate the old string 'Swipe here to dismiss';
